import { parentPort } from 'node:worker_threads';
import { quadgramScore } from './english-frequency';

// Minimal LCG for the worker
function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s;
  };
}

function isWhitespace(c: string): boolean {
  return (
    c === ' ' ||
    c === '\t' ||
    c === '\n' ||
    c === '\r' ||
    c === '\f' ||
    c === '\v'
  );
}

function decryptWithMapping(ciphertext: string, mapping: Map<string, string>): string {
  let out = '';
  for (let i = 0; i < ciphertext.length; i++) {
    const c = ciphertext[i];
    if (isWhitespace(c)) {
      out += c;
      continue;
    }
    const letter = mapping.get(c);
    out += letter ?? c;
  }
  return out;
}

// ... Re-implementing the inner loop logic or importing it ...
// To be safe and avoid the TS loader issue in workers if possible, 
// let's just make the worker a thin wrapper that imports the logic 
// and see if the 'execArgv' trick works for this file too.

import { solveHomophonicSubstitution } from './homophonic-substitution-solver';

if (!parentPort) {
  throw new Error('This file must be run as a worker thread');
}

parentPort.on('message', (msg) => {
  if (msg.type === 'shutdown') {
    process.exit(0);
  }

  if (msg.type === 'solve') {
    try {
      const result = solveHomophonicSubstitution({
        ...msg.args,
        forks: 1, // One fork per worker task
      });
      parentPort!.postMessage({
        type: 'done',
        taskId: msg.taskId,
        result: {
          score: result.score,
          plaintext: result.plaintext,
          mapping: Array.from(result.mapping.entries()),
          swapCount: result.candidates[0].swapCount,
        },
      });
    } catch (err) {
      parentPort!.postMessage({
        type: 'error',
        taskId: msg.taskId,
        error: (err as Error).message,
      });
    }
  }
});

parentPort.postMessage({ type: 'ready' });
